import { useState, useCallback, useRef, useEffect } from 'react';
import { motion } from 'framer-motion';
import ShpeHatAnimation from './ShpeHatAnimation';

export default function Home() {
  const [stage, setStage] = useState('video'); // 'video' | 'hat' | 'home'
  const [fadeOut, setFadeOut] = useState(false);
  const videoRef = useRef(null);

  useEffect(() => {
    if (videoRef.current) {
      videoRef.current.playbackRate = 1.5;
    }
  }, []);

  const handleVideoEnd = useCallback(() => {
    setFadeOut(true);
    setTimeout(() => {
      setFadeOut(false);
      setStage('hat');
    }, 600);
  }, []);

  const handleHatComplete = useCallback(() => {
    setFadeOut(true);
    setTimeout(() => {
      setFadeOut(false);
      setStage('home');
    }, 800);
  }, []);

  return (
    <main className="font-sans">
      {stage === 'video' && (
        <div
          style={{
            transition: 'opacity 0.6s ease',
            opacity: fadeOut ? 0 : 1,
            width: '100%',
            height: '100vh',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            overflow: 'hidden',
          }}
        >
          <video
            ref={videoRef}
            src={require('../assets/shpe_animated_video.mp4')}
            autoPlay
            muted
            playsInline
            onEnded={handleVideoEnd}
            style={{ width: '100%', height: '100%', objectFit: 'cover' }}
          />
        </div>
      )}

      {stage === 'hat' && (
        <div
          style={{
            transition: 'opacity 0.6s ease',
            opacity: fadeOut ? 0 : 1,
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
            minHeight: '100vh',
          }}
        >
          <ShpeHatAnimation onComplete={handleHatComplete} speed={1.8} />
        </div>
      )}

      {stage === 'home' && (
        <motion.section
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 0.8 }}
          className="flex flex-col items-center justify-center min-h-screen text-center px-6"
        >
          <h1 className="text-4xl font-bold text-blue-700 mb-4">SHPE Austin</h1>
          <p className="text-gray-600 text-lg">Welcome to the SHPE Austin website.</p>
        </motion.section>
      )}
    </main>
  );
}
